examples.code:
// Extended with label and custom icon
<FAB
  variant="extended"
  label="New post"
  icon={EditIcon}
  position="bottom-center"
  onPress={handleCreate}
/>

// Square shaped FAB at top-right corner
<FAB
  shape="square"
  icon={FilterIcon}
  position="top-right"
  onPress={openFilters}
/>

// Disabled FAB while upload is in progress
<FAB
  icon={UploadIcon}
  onPress={handleUpload}
  disabled={isUploading}
  label="Upload"
  variant="extended"
/>
